<template lang="en">
  <div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
      <div ref="hellp" id="divMaindealData">
        <div class="border p-3">
          <Form ref="JobPostForm">
            <dynamic-form
              lang="en"
              ref="BarcodeReport"
              v-if="DataLoaded"
              :buttons="buttons"
              :schema="FormSchema"
              v-on:OnSubmit="onSubmit"
              :mandatorytext="MandatoryString"
            />

            <div class="row placeholder">
              <div class="col-md-12 p-0">
                <ReportViewer
                  v-if="parameter.length > 0"
                  :key="loadKey"
                  :viewerId="'viewer_' + loadKey"
                  :parameter="parameter"
                  :reportPath="reportPath"
                />
              </div>
            </div>
          </Form>
        </div>
      </div>
    </section>
  </div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';

import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';

export default {
    components: { ReportViewer },

    data() {
        return {
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            isLoading: false,
            reportPath: null,
            parameter: [],
            DataLoaded: 0,
            loadKey: 0,

            FormSchema: [
                {
                    layoutType: "triple",
                    Data: [
                        {
                            astype: "SearchableSelectField",
                            label: this.$t("Client"),
                            name: "ContractName",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Client'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: { clear: true },
                                isMultiple: false,
                                minSearchLength: 0,
                                onChange: this.onSelectionChange
                            },
                            validationRules: { required: false }
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t("Utility Name"),
                            name: "UtilityName",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Utility Name'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                groupFields: [],
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                },
                                isMultiple: true,
                                minSearchLength: 0
                            }
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t("Billing Rule"),
                            name: "BillingRule",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Billing Rule'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                groupFields: [],
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                },
                                isMultiple: true,
                                minSearchLength: 0
                            }
                        }
                    ]
                },
                {
                    layoutType: "triple",
                    Data: [
                        {
                            astype: "EmptyField",
                            visibility: true
                        },
                        {
                            astype: "EmptyField",
                            visibility: true
                        },
                        {
                            astype: "EmptyField",
                            visibility: true
                        }
                    ]
                }
            ],

            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search"
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ]
        };
    },

    created() {
        this.userId = this.GetUserInfo.ID;
        this.companyId = this.GetUserInfo.CompanyId;
        this.UserType = this.GetUserInfo.UserType;

        this.DataLoaded = 1;
        this.GetClient();
        this.GetBillingRuleListByCompanyId();
    },

    methods: {
        /* =======================
           Helpers
        ======================= */
        /* =======================
           Submit
        ======================= */
        async onSubmit(e) {
            const vm = this;
            vm.isLoading = true;
            vm.loadKey = Date.now();
            vm.reportPath = '';
            vm.parameter = [];

            let myObj = {
                reportName: "billingrulesmissinglimitsreport",
                ContractId: e.ContractName || '',
                UtilityIds: e.UtilityName && e.UtilityName.length > 0 ? e.UtilityName.join(",") : '',
                RuleName: e.BillingRule && e.BillingRule.length > 0 ? e.BillingRule.join(",") : ''
            };

            DataServices.ReportMain(JSON.stringify(myObj))
                .then(response => {
                    vm.reportPath = response.data.reportpath;
                    vm.parameter = response.data.parameters;
                    vm.isLoading = false;
                })
                .catch(error => {
                    console.error("Error loading report:", error);
                    vm.isLoading = false;
                });
        },

        /* =======================
           Clear
        ======================= */
        ClearAll() {
            const vm = this;

            vm.$refs.BarcodeReport.updateProperty("ContractName", "value", '');
            vm.$refs.BarcodeReport.updateProperty("UtilityName", "value", '');
            vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", []);
            vm.$refs.BarcodeReport.updateProperty("BillingRule", "value", '');

            vm.reportPath = '';
            vm.parameter = [];
            vm.$refs.BarcodeReport.validateForm.reset();
        },

        /* =======================
           Dropdown loaders
        ======================= */
        GetClient() {
            const vm = this;
            const params = 'pageNumber=&pageSize=&Reqfrom=CUSTOMREPORT&search=null&userId=null';

            DataServices.GetClient(params).then(response => {
                const options = response.data.map(item => ({
                    text: item.CHILD_NAME,
                    value: item.CHILD_USER_ID,
                    status: 'Active'
                }));

                vm.$refs.BarcodeReport.updateProperty(
                    "ContractName",
                    "config.options",
                    options
                );
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }).catch(error => {
                console.error('Error fetching clients:', error);
                vm.$refs.BarcodeReport.updateProperty("ContractName", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        },

        onSelectionChange(value, selectedValue) {
            const vm = this;

            vm.$refs.BarcodeReport.updateProperty("UtilityName", "value", '');
            vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", []);

            if (selectedValue) {
                vm.GetUtilityByClient(selectedValue);
            }
        },

        GetUtilityByClient(clientId) {
            const vm = this;
            const url = `clientId=${clientId}&configid=0&Reqfrom=&clientIds=`;

            DataServices.GetUtilityByClient(url).then(response => {
                const options = response.data.map(item => ({
                    text: item.UTILITY_NAME,
                    value: item.UTILITY_ID,
                    status: 'Active'
                }));

                vm.$refs.BarcodeReport.updateProperty(
                    "UtilityName",
                    "config.options",
                    options
                );
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }).catch(error => {
                console.error('Error fetching utilities:', error);
                vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        },

        GetBillingRuleListByCompanyId() {
            const vm = this;

            DataServices.GetBillingRuleListByCompanyId().then(response => {
                const options = response.data.map(item => ({
                    text: item.BILLINGRULE,
                    value: item.BILLINGRULE_ID,
                    status: 'Active'
                }));

                vm.$refs.BarcodeReport.updateProperty(
                    "BillingRule",
                    "config.options",
                    options
                );
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }).catch(error => {
                console.error('Error fetching billing rules:', error);
                vm.$refs.BarcodeReport.updateProperty("BillingRule", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        }
    }
};
</script>