<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                          <ReportViewer
                                v-if="parameter.length > 0"
                                :key="loadKey"
                                :viewerId="'viewer_' + loadKey"
                                :parameter="parameter"
                                :reportPath="reportPath">
                            </ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>
<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            isLoading: false,
            loadKey: 0,
            reportPath: null,
            parameter: [],
            DataLoaded: 0,
            FormSchema: [{
                layoutType: "triple",
                Data: [{
                        astype: "SearchableSelectField",
                        label: this.$t("Client"),
                        name: "ContractName",
                        value: "",
                        placeholder: this.$t('Select') + " " + this.$t('Client'),
                        visibility: true,
                        isSearch: false,
                        config: {
                            options: [],
                            isMultiple: false,
                            minSearchLength: 0,
                            groupFields: [],
                            actionButtons: {
                                clear: true
                            },
                            onChange: this.onSelectionChange
                        },
                        validationRules: {
                            required: true
                        }
                    },
                    {
                        astype: "SearchableSelectField",
                        label: this.$t("Utility Name"),
                        name: "UtilityName",
                        value: "",
                        placeholder: this.$t('Select') + " " + this.$t('Utility Name'),
                        visibility: true,
                        isSearch: false,
                        config: {
                            options: [],
                            isMultiple: true,
                            minSearchLength: 0,
                            groupFields: [],
                            actionButtons: {
                                selectAll: true,
                                clear: true
                            }
                        },
                        validationRules: {
                            required: false
                        }
                    },
                    {
                        astype: "SearchableSelectField",
                        label: this.$t("State"),
                        name: "State",
                        value: "",
                        placeholder: this.$t('Select') + " " + this.$t('State'),
                        visibility: true,
                        isSearch: false,
                        config: {
                            options: [],
                            isMultiple: false,
                            minSearchLength: 0,
                            groupFields: [],
                            actionButtons: {
                                clear: true
                            }
                        },
                        validationRules: {
                            required: false
                        }
                    },
                    {
                        astype: "SearchableSelectField",
                        label: this.$t("Work Code"),
                        name: "WorkCode",
                        value: "",
                        placeholder: this.$t('Select') + " " + this.$t('WorkCode'),
                        visibility: true,
                        isSearch: false,
                        config: {
                            options: [],
                            isMultiple: false,
                            minSearchLength: 0,
                            groupFields: [],
                            actionButtons: {
                                clear: true
                            }
                        },
                        validationRules: {
                            required: false
                        }
                    }
                ]
            }],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DataLoaded = 1;
        await vm.GetClient();
        await vm.GetDDLStateList();
        await vm.GetWorkCodeInfo();
    },
    methods: {
        async onSubmit(e) {
            var vm = this;
            vm.isLoading = true;
            vm.loadKey = Date.now();
            vm.reportPath = '';
            vm.parameter = [];
            let myObj = {
                reportName: "msisingratesinworkcodereport",
                ClientIds: e.ContractName ? e.ContractName : '',
                UtilityIds: e.UtilityName && e.UtilityName.length > 0 ? e.UtilityName.join(",") : '',
                State: e.State ? e.State : '',
                WorkCodeId: e.WorkCode ? e.WorkCode : '',
            }
            var postString = JSON.stringify(myObj);
            try {
                let response = await DataServices.ReportMain(postString);
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
            } catch (error) {
                console.error("Error loading report:", error);
            } finally {
                vm.isLoading = false;
            }
        },
        ClearAll: function () {
            var vm = this;
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[1].config.options = [];
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[0].Data[3].value = '';
            vm.reportPath = '';
            vm.parameter = [];
            vm.loadKey = 0;
            vm.$refs.BarcodeReport.validateForm.reset();
        },
        async GetClient() {
            var vm = this;
            var params = 'pageNumber=&pageSize=&Reqfrom="CUSTOM"&search=null&userId=null';
            try {
                let response = await DataServices.GetClient(params);
                if (response.data && response.data.length > 0) {
                    let clientOptions = response.data.map(item => ({
                        text: item.CHILD_NAME,
                        displayValue: item.CHILD_NAME,
                        value: item.CHILD_USER_ID,
                        description: null,
                        groupText: null,
                        groupValue: null,
                        metaData: null
                    }));
                    if (vm.$refs.BarcodeReport) {
                        vm.$refs.BarcodeReport.updateProperty("ContractName", "config.options", clientOptions);
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                } else {
                    if (vm.$refs.BarcodeReport) {
                        vm.$refs.BarcodeReport.updateProperty("ContractName", "config.options", []);
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                }
            } catch (error) {
                console.error("Error fetching clients:", error);
                if (vm.$refs.BarcodeReport) {
                    vm.$refs.BarcodeReport.updateProperty("ContractName", "config.options", []);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            }
        },
        async onSelectionChange(value, selectedId) {
            var vm = this;
            if (vm.$refs.BarcodeReport) {
                vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", []);
                vm.$refs.BarcodeReport.updateProperty("UtilityName", "value", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
            if (selectedId && selectedId > 0) {
                var url = `clientId=${selectedId}&configid=0&Reqfrom=&clientIds=`;
                try {
                    let response = await DataServices.GetUtilityByClient(url);
                    if (response.data && response.data.length > 0) {
                        let utilityOptions = response.data.map(item => ({
                            text: item.UTILITY_NAME,
                            displayValue: item.UTILITY_NAME,
                            value: item.UTILITY_ID,
                            description: null,
                            groupText: null,
                            groupValue: null,
                            metaData: null
                        }));
                        if (vm.$refs.BarcodeReport) {
                            vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", utilityOptions);
                            vm.$refs.BarcodeReport.UpdateKeyValue();
                        }
                    }
                } catch (error) {
                    console.error("Error fetching utilities:", error);
                    if (vm.$refs.BarcodeReport) {
                        vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", []);
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                }
            }
        },
        async GetDDLStateList() {
            var vm = this;
            var params = `CountryId=223&InclueCandaState=true`;
            try {
                let response = await DataServices.GetDDLStateList(params);
                if (response.data && response.data.length > 0) {
                    let stateOptions = response.data.map(item => ({
                        text: item.STATE_NAME + '(' + item.ISO_CODE_3 + ')',
                        displayValue: item.STATE_NAME + '(' + item.ISO_CODE_3 + ')',
                        value: item.ISO_CODE_3,
                        description: null,
                        groupText: null,
                        groupValue: null,
                        metaData: null
                    }));
                    if (vm.$refs.BarcodeReport) {
                        vm.$refs.BarcodeReport.updateProperty("State", "config.options", stateOptions);
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                } else {
                    if (vm.$refs.BarcodeReport) {
                        vm.$refs.BarcodeReport.updateProperty("State", "config.options", []);
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                }
            } catch (error) {
                console.error("Error fetching states:", error);
                if (vm.$refs.BarcodeReport) {
                    vm.$refs.BarcodeReport.updateProperty("State", "config.options", []);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            }
        },
        async GetWorkCodeInfo() {
            var vm = this;
            try {
                let response = await DataServices.GetWorkCodeInfo();
                if (response.data && response.data.length > 0) {
                    let workCodeOptions = response.data.map(item => ({
                        text: item.work_code,
                        displayValue: item.work_code,
                        value: item.work_code_id,
                        description: null,
                        groupText: null,
                        groupValue: null,
                        metaData: null
                    }));
                    if (vm.$refs.BarcodeReport) {
                        vm.$refs.BarcodeReport.updateProperty("WorkCode", "config.options", workCodeOptions);
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                } else {
                    if (vm.$refs.BarcodeReport) {
                        vm.$refs.BarcodeReport.updateProperty("WorkCode", "config.options", []);
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                }
            } catch (error) {
                console.error('Error fetching work code list:', error);
                if (vm.$refs.BarcodeReport) {
                    vm.$refs.BarcodeReport.updateProperty("WorkCode", "config.options", []);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            }
        }
       
    }
};
</script>