<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                           <ReportViewer 
                                v-if="parameter.length > 0" 
                                :key="loadKey"
                                :viewerId="'viewer_' + loadKey"
                                :parameter="parameter" 
                                :reportPath="reportPath">
                            </ReportViewer>  
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            isLoading: false,
            reportPath: null,
            parameter: [],
            DataLoaded: 0,
            loadKey: 0,
            FormSchema: [{
                layoutType: "triple",
                Data: [{
                        astype: "SearchableSelectField",
                        label: this.$t("Project"),
                        name: "Project",
                        value: "",
                        placeholder: this.$t('Select') + " " + this.$t('Project'),
                        visibility: true,
                        isSearch: false,
                        config: {
                            options: [],
                            isMultiple: true,
                            minSearchLength: 0,
                            groupFields: [],
                            actionButtons: {
                                selectAll: true,
                                clear: true
                            }
                        },
                        validationRules: {
                            required: false
                        }
                    },
                    {
                        astype: "SearchableSelectField",
                        label: this.$t("Status"),
                        name: "Status",
                        value: "",
                        placeholder: this.$t('Select') + " " + this.$t('Status'),
                        visibility: true,
                        isSearch: false,
                        config: {
                            options: [],
                            isMultiple: true,
                            minSearchLength: 0,
                            groupFields: [],
                            actionButtons: {
                                selectAll: true,
                                clear: true
                            }
                        },
                        validationRules: {
                            required: false
                        }
                    }
                ]
            }],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ]
        }
    },
    async created() {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DataLoaded = 1;
    },
    async mounted() {
        await this.GetProjectByCompanyIdAndUserId();
        await this.GetStatusList();
    },
    methods: {
        ClearAll: function () {
            var vm = this;
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            vm.reportPath = '';
            vm.parameter = [];
            vm.loadKey = 0;
            vm.$refs.BarcodeReport.validateForm.reset();  
        },
        async onSubmit(e) {
            var vm = this;
            vm.isLoading = true;
            vm.loadKey = Date.now();
            vm.reportPath = '';
            vm.parameter = [];
            let myObj = {
                reportName: "milestonereport",
                projectIds: e.Project && e.Project.length > 0 ? e.Project.join(",") : '',
                statusIds: e.Status && e.Status.length > 0 ? e.Status.join(",") : ''
            }

            var postString = JSON.stringify(myObj);
            try {
                let response = await DataServices.ReportMain(postString);
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
            } catch (error) {
                console.error("Error loading report:", error);
            } finally {
                vm.isLoading = false;
            }
        },
        async GetProjectByCompanyIdAndUserId() {
            var vm = this;
            try {
                let response = await DataServices.GetProjectByCompanyIdAndUserId();
                if (response.data && response.data.length > 0) {
                    let projectOptions = response.data.map(item => ({
                        text: item.projectName,
                        displayValue: item.projectName,
                        value: item.projectId,
                        description: null,
                        groupText: null,
                        groupValue: null,
                        metaData: null
                    }));
                    vm.$refs.BarcodeReport.updateProperty("Project", "config.options", projectOptions);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                } else {
                    vm.$refs.BarcodeReport.updateProperty("Project", "config.options", []);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } catch (error) {
                console.error("Error fetching projects:", error);
                vm.$refs.BarcodeReport.updateProperty("Project", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        },
        async GetStatusList() {
            var vm = this;
            var url = `langCode=en&statusType=Milestone&hasglobal=false`
            try {
                let response = await DataServices.GetStatusList(url);
                if (response.data && response.data.length > 0) {
                    let statusOptions = response.data.map(item => ({
                        text: item.STATUS,
                        displayValue: item.STATUS,
                        value: item.STATUS_ID,
                        description: null,
                        groupText: null,
                        groupValue: null,
                        metaData: null
                    }));
                    vm.$refs.BarcodeReport.updateProperty("Status", "config.options", statusOptions);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                } else {
                    vm.$refs.BarcodeReport.updateProperty("Status", "config.options", []);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } catch (error) {
                console.error("Error fetching status list:", error);
                vm.$refs.BarcodeReport.updateProperty("Status", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        }
    }
};
</script>