<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext='MandatoryString'></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer v-if="parameter.length > 0" :key="loadKey" :viewerId="'viewer_' + loadKey" :parameter="parameter" :reportPath="reportPath">
                            </ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
</div>
</section>
</div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
import moment from 'moment';
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            isLoading: false,
            loadKey: 0,
            reportPath: null,
            parameter: [],
            ClientData: [],
            DataLoaded: 0,
            ClientIds: '',
            FormSchema: [{
                    layoutType: "triple",
                    Data: [{
                            astype: "SearchableSelectField", 
                             label: "Contract Name",
                            name: "ContractName",
                            value: "",
                            placeholder: this.$t('SelectClient'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: true,
                                    active: true,
                                    inactive: true,
                                    clear: true
                                },
                                isMultiple: false,
                                groupFields: ['groupText'],
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                                onChange: this.onContractChange 
                            },
                            validationRules: {
                                "required": true
                            },
                        },
                        {
                            astype: "SearchableSelectField", 
                            label: "Utility Name",
                            name: "UtilityName",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Utility Name'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                },
                                groupFields: [],
                                isMultiple: true, 
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "SearchableSelectField", 
                            label: "Invoice Grouping",
                            name: "InvoiceGrouping",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Invoice Grouping'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                },
                                groupFields: [],
                                isMultiple: true, 
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        }
                    ]
                },
                {
                    layoutType: "triple",
                    Data: [{
                            astype: "SearchableSelectField", 
                            label: "Cost Centers",
                            name: "CostCenter",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Cost Centers'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                },
                                groupFields: [],
                                isMultiple: true, 
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "DateRangeField",
                            label: this.$t('Invoice Date'),
                            name: "InvoiceDateFrom",
                            value: "",
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                maxDate: false,
                                onChange: this.setTimerDate,
                                datePickerConfig: {
                                    useCurrent: true,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                                secondDatePickerConfig: {
                                    useCurrent: false,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "SearchableSelectField", 
                            label: this.$t("State"),
                            name: "State",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('State'),
                            visibility: true,
                            isSearch: true,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: true,
                                    active: true,
                                    inactive: true,
                                    clear: true
                                },
                                groupFields: [],
                                isMultiple: true, 
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        }
                    ]
                }
            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DataLoaded = 1;
        await vm.fetchclientlist(); 
        await vm.GetDDLStateList();
        await vm.GetCostCenters();
    },
    methods: {
        setTimerDate: function (x, y, z) {
            var vm = this;
            if (y.name == "InvoicedtFrom") {
                vm.$refs.BarcodeReport.updateProperty("InvoicedtTo", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        },
        formatDate(value) {
            if (!value) return null;
            const m = moment(value);
            return m.isValid() ? m.format('MM-DD-YYYY') : null;
        },
        onSubmit(e) {
            var vm = this;
            vm.isLoading = true;
            vm.loadKey = Date.now();
            vm.reportPath = '';
            vm.parameter = [];

            vm.InvoiceDateFrom = vm.$refs.BarcodeReport.getPropertyValue("InvoiceDateFrom", "value");
            vm.InvoiceDateTo = vm.$refs.BarcodeReport.getPropertyValue("InvoiceDateFrom", "secondValue");

            let myObj = {
                reportName: "monthlyrevenuedetailreport",
                ClientIds: e.ContractName, 
                UtilityIds: e.UtilityName.length > 0 ? e.UtilityName.join(",") : '',  
                DivisionId: e.InvoiceGrouping.length > 0 ? e.InvoiceGrouping.join(",") : '',  
                CostCenterId: e.CostCenter.length > 0 ? e.CostCenter.join(",") : '',  
                dateFrom: vm.formatDate(vm.InvoiceDateFrom),
                dateTo: vm.formatDate(vm.InvoiceDateTo),
                State: e.State.length > 0 ? e.State.join(",") : '',
            }
            var postString = JSON.stringify(myObj);
            DataServices.ReportMain(postString).then(function (response) {
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
                vm.isLoading = false;
            }).catch(function (error) {
                console.error("Error loading report:", error);
                vm.isLoading = false;
            });
        },

        ClearAll: function () {
            var vm = this;
        
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[1].config.options = []; 
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[0].Data[2].config.options = []; 
            (vm.FormSchema)[1].Data[0].value = '';
            (vm.FormSchema)[1].Data[1].value = '';
            (vm.FormSchema)[1].Data[1].secondValue = '';
            (vm.FormSchema)[1].Data[2].value = '';
            vm.reportPath = '';
            vm.parameter = [];
            vm.loadKey = 0;
            vm.$refs.BarcodeReport.validateForm.reset();
        },
        
        
        onContractChange(value, x) {
            var vm = this;
            vm.isLoading = true;
            vm.selectedClientId = x; 
            vm.ClientIds = x;
            
            if (vm.selectedClientId) {
                var url = `clientId=${vm.selectedClientId}&configId=&reqFrom=&clientIds=`;
               
                vm.GetUtilityByClient(url);
                vm.GetDivisionListByCilentId();
            } else {
         
                vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", []);
                vm.$refs.BarcodeReport.updateProperty("UtilityName", "value", '');
                vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "config.options", []);
                vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "value", '');
                vm.isLoading = false;
            }
        },
        
     
        fetchclientlist: function () {
            var vm = this;
            vm.isLoading = true;
            var params = 'pageNumber=&pageSize=&Reqfrom="CUSTOM"&search=null&userId=null';
            DataServices.GetClient(params).then(response => {
                vm.isLoading = false;
                vm.ClientData = response.data;
                let ClientOptions = [];
                if (vm.ClientData.length > 0) {
                    vm.ClientData.forEach(element => {
                        let obj = {
                            description: null,
                            displayValue: element.CHILD_NAME,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: element.CHILD_NAME,
                            value: element.CHILD_USER_ID,
                            status: 'Active' 
                        };
                        ClientOptions.push(obj);
                    });
                }
                vm.$refs.BarcodeReport.updateProperty("ContractName", "config.options", ClientOptions);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }).catch(error => {
                vm.isLoading = false;
                vm.ClientData = [];
                vm.$refs.BarcodeReport.updateProperty("ContractName", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
                console.error('Error fetching client list:', error);
            });
        },
        
        GetUtilityByClient: function (url) {
            var vm = this;
            DataServices.GetUtilityByClient(url).then(response => {
                let SelectedUtilityList = [];
                var UtilityList = response.data;
                if (UtilityList != null && UtilityList.length > 0) {
                    UtilityList.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.UTILITY_NAME,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.UTILITY_NAME,
                            value: item.UTILITY_ID,
                            status: 'Active'
                        };
                        SelectedUtilityList.push(obj);
                    });
                    vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", SelectedUtilityList);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
                vm.isLoading = false;
            }).catch(error => {
                vm.isLoading = false;
                vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", []);
                vm.$refs.BarcodeReport.updateProperty("UtilityName", "value", '');
                console.error('Error fetching utility list:', error);
            });
        },
        
        GetDivisionListByCilentId: async function () {
            var vm = this;
            if (vm.selectedClientId) {
                var url = `clientId=${vm.selectedClientId}`;
                await DataServices.GetDivisionListByCilentId(url).then((response) => {
                    if (response.data.length > 0) {
                        var DivisionData = response.data;
                        let DivisionOptions = [];
                        DivisionData.forEach(element => {
                            let obj = {
                                description: null,
                                displayValue: element.NAME,
                                groupText: null,
                                groupValue: null,
                                metaData: null,
                                text: element.NAME,
                                value: element.DIVISIONS_ID,
                                status: 'Active'
                            };
                            DivisionOptions.push(obj);
                        });
                        vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "config.options", DivisionOptions);
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                    vm.isLoading = false;
                }).catch((error) => {
                    vm.isLoading = false;
                    vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "config.options", []);
                    vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "value", '');
                    console.error("Error fetching divisions:", error);
                });
            } else {
                vm.isLoading = false;
            }
        },
        
        GetCostCenters: async function () {
            var vm = this;
            await DataServices.GetCostCenters().then((response) => {
                if (response.data != '') {
                    var CostCentresData = response.data;
                    let CostCenterOptions = [];
                    CostCentresData.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.text,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.text,
                            value: item.value,
                            status: 'Active'
                        };
                        CostCenterOptions.push(obj);
                    });
                    vm.$refs.BarcodeReport.updateProperty("CostCenter", "config.options", CostCenterOptions);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        
        GetDDLStateList: async function () {
            var vm = this;
            var params = `CountryId=223&InclueCandaState=true`;
            DataServices.GetDDLStateList(params).then((response) => {
                if (response.data.length > 0) {
                    var StateData = response.data;
                    let StateOptions = [];
                    StateData.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.STATE_NAME + '(' + item.ISO_CODE_3 + ')',
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.STATE_NAME + '(' + item.ISO_CODE_3 + ')',
                            value: item.ISO_CODE_3,
                            status: 'Active'
                        };
                        StateOptions.push(obj);
                    });
                    vm.$refs.BarcodeReport.updateProperty("State", "config.options", StateOptions);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        }
    }
}
</script>