<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer v-if="parameter.length > 0" :key="loadKey" :viewerId="'viewer_' + loadKey" :parameter="parameter" :reportPath="reportPath">
                            </ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>
<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
import moment from 'moment';
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            isLoading: false,
            reportPath: null,
            parameter: [],
            DataLoaded: 0,
            loadKey: 0,
            FormSchema: [{
                layoutType: "triple",
                Data: [{
                        astype: "SearchableSelectField",
                        label: "Client",
                        name: "Client",
                        value: "",
                        placeholder: this.$t('Select'),
                        visibility: true,
                        isSearch: false,
                        config: {
                            options: [],
                            isMultiple: false,
                            minSearchLength: 0,
                            groupFields: [],
                            actionButtons: {
                                clear: true
                            }
                        },
                        validationRules: {
                            required: false
                        }
                    },
                    {
                        astype: "DateRangeField",
                        label: this.$t('Invoice Date'),
                        name: "InvoiceDateFrom",
                        value: "",
                        placeholder: "",
                        config: {
                            format: "MM/DD/YYYY",
                            maxDate: false,
                            onChange: this.setTimerDate,
                            datePickerConfig: {
                                useCurrent: true,
                                showClear: true,
                                showClose: true,
                                allowInputToggle: false,
                                minDate: true,
                                maxDate: true,
                                widgetPositioning: {
                                    horizontal: 'right',
                                    vertical: 'bottom'
                                }
                            },
                            secondDatePickerConfig: {
                                useCurrent: false,
                                showClear: true,
                                showClose: true,
                                allowInputToggle: false,
                                minDate: true,
                                maxDate: true,
                                widgetPositioning: {
                                    horizontal: 'right',
                                    vertical: 'bottom'
                                }
                            },
                        },
                        validationRules: {
                            "required": false
                        },
                    },
                    {
                        astype: "SearchableSelectField",
                        label: this.$t("State"),
                        name: "State",
                        value: "",
                        placeholder: this.$t('Select'),
                        visibility: true,
                        isSearch: false,
                        config: {
                            options: [],
                            isMultiple: true,
                            minSearchLength: 0,
                            groupFields: [],
                            actionButtons: {
                                selectAll: true,
                                clear: true
                            }
                        },
                        validationRules: {
                            required: false
                        }
                    },
                    {
                        astype: "DateRangeField",
                        label: this.$t('Import Date'),
                        name: "ImportDateFrom",
                        value: "",
                        placeholder: "",
                        config: {
                            format: "MM/DD/YYYY",
                            maxDate: false,
                            onChange: this.setTimerDate,
                            datePickerConfig: {
                                useCurrent: true,
                                showClear: true,
                                showClose: true,
                                allowInputToggle: false,
                                minDate: true,
                                maxDate: true,
                                widgetPositioning: {
                                    horizontal: 'right',
                                    vertical: 'bottom'
                                }
                            },
                            secondDatePickerConfig: {
                                useCurrent: false,
                                showClear: true,
                                showClose: true,
                                allowInputToggle: false,
                                minDate: true,
                                maxDate: true,
                                widgetPositioning: {
                                    horizontal: 'right',
                                    vertical: 'bottom'
                                }
                            },
                        },
                        validationRules: {
                            "required": false
                        },
                    }
                ]
            }],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DataLoaded = 1;
        await vm.GetClient();
        await vm.GetDDLStateList();
    },
    methods: {
        setTimerDate: function (x, y, z) {
            var vm = this;
            if (y.name == "InvoiceDateFrom") {
                vm.$refs.BarcodeReport.updateProperty("InvoiceDateFrom", "config.secondDatePickerConfig.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
            if (y.name == "ImportDateFrom") {
                vm.$refs.BarcodeReport.updateProperty("ImportDateFrom", "config.secondDatePickerConfig.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        },
        ClearAll: function () {
            var vm = this;
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[1].secondValue = '';
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[0].Data[3].value = '';
            (vm.FormSchema)[0].Data[3].secondValue = '';
            vm.reportPath = '';
            vm.parameter = [];
            vm.loadKey = 0;
            vm.$refs.BarcodeReport.validateForm.reset();
        },
        async GetClient() {
            var vm = this;
            var params = 'pageNumber=&pageSize=&Reqfrom=null&search=null&userId=null';
            try {
                let response = await DataServices.GetClient(params);
                if (response.data && response.data.length > 0) {
                    let clientOptions = response.data.map(item => ({
                        text: item.CHILD_NAME,
                        displayValue: item.CHILD_NAME,
                        value: item.CHILD_USER_ID,
                        description: null,
                        groupText: null,
                        groupValue: null,
                        metaData: null
                    }));
                    vm.$refs.BarcodeReport.updateProperty("Client", "config.options", clientOptions);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                } else {
                    vm.$refs.BarcodeReport.updateProperty("Client", "config.options", []);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } catch (error) {
                console.error("Error fetching clients:", error);
                vm.$refs.BarcodeReport.updateProperty("Client", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        },
        async GetDDLStateList() {
            var vm = this;
            var params = `CountryId=223&InclueCandaState=true`;
            try {
                let response = await DataServices.GetDDLStateList(params);
                if (response.data && response.data.length > 0) {
                    let stateOptions = response.data.map(item => ({
                        text: item.STATE_NAME + '(' + item.ISO_CODE_3 + ')',
                        displayValue: item.STATE_NAME + '(' + item.ISO_CODE_3 + ')',
                        value: item.ISO_CODE_3,
                        description: null,
                        groupText: null,
                        groupValue: null,
                        metaData: null
                    }));
                    vm.$refs.BarcodeReport.updateProperty("State", "config.options", stateOptions);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                } else {
                    vm.$refs.BarcodeReport.updateProperty("State", "config.options", []);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } catch (error) {
                console.error("Error fetching states:", error);
                vm.$refs.BarcodeReport.updateProperty("State", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        },
        formatDate(value) {
            if (!value) return null;
            const m = moment(value);
            return m.isValid() ? m.format('MM-DD-YYYY') : null;
        },
        async onSubmit(e) {
            var vm = this;
            vm.isLoading = true;
            vm.loadKey = Date.now();
            vm.reportPath = '';
            vm.parameter = [];
            vm.InvoiceDateFrom = vm.$refs.BarcodeReport.getPropertyValue("InvoiceDateFrom", "value");
            vm.InvoiceDateTo = vm.$refs.BarcodeReport.getPropertyValue("InvoiceDateFrom", "secondValue");
            vm.ImportDateFrom = vm.$refs.BarcodeReport.getPropertyValue("ImportDateFrom", "value");
            vm.ImportDateTo = vm.$refs.BarcodeReport.getPropertyValue("ImportDateFrom", "secondValue");
            let myObj = {
                reportName: "msisingratesreport",
                ClientIds: e.Client ? e.Client : '',
                dateFrom: vm.formatDate(vm.InvoiceDateFrom),
                dateTo: vm.formatDate(vm.InvoiceDateTo),
                State: e.State && e.State.length > 0 ? e.State.join(",") : '',
                importDateFrom: vm.formatDate(vm.ImportDateFrom),
                importdateTo: vm.formatDate(vm.ImportDateTo)
            }
            var postString = JSON.stringify(myObj);
            try {
                let response = await DataServices.ReportMain(postString);
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
            } catch (error) {
                console.error("Error loading report:", error);
            } finally {
                vm.isLoading = false;
            }
        }
    }
};
</script>