<template lang="en">
  <div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
      <div ref="hellp" id="divMaindealData">
        <div class="border p-3">
          <Form ref="JobPostForm">
            <dynamic-form
              lang="en"
              ref="BarcodeReport"
              v-if="DataLoaded"
              :buttons="buttons"
              :schema="FormSchema"
              v-on:OnSubmit="onSubmit"
              :mandatorytext="MandatoryString"
            />

            <div class="row placeholder">
              <div class="col-md-12 p-0">
                <ReportViewer
                  v-if="parameter.length > 0"
                  :key="loadKey"
                  :viewerId="'viewer_' + loadKey"
                  :parameter="parameter"
                  :reportPath="reportPath"
                />
              </div>
            </div>
          </Form>
        </div>
      </div>
    </section>
  </div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';

import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
import moment from 'moment';

export default {
  components: { ReportViewer },

  data() {
    return {
      MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
      isLoading: false,
      reportPath: null,
      parameter: [],
      DataLoaded: 0,
      loadKey: 0,

      FormSchema: [
        {
          layoutType: "triple",
          Data: [
            {
              astype: "SearchableSelectField",
              label: this.$t("Contract Name"),
              name: "ContractName",
              value: "",
              placeholder: this.$t("Select"),
              visibility: true,
              isSearch: false,
              config: {
                options: [],
                actionButtons: { clear: true },
                isMultiple: false,
                minSearchLength: 0,
                onChange: this.onContractChange
              },
              validationRules: { required: true }
            },
            {
              astype: "SearchableSelectField",
              label: this.$t("Invoice Grouping"),
              name: "InvoiceGrouping",
              value: "",
              placeholder: this.$t("Select"),
              visibility: true,
              isSearch: false,
              config: {
                options: [],
                actionButtons: { clear: true },
                isMultiple: false,
                minSearchLength: 0
              }
            },
            {
              astype: "SearchableSelectField",
              label: this.$t("Invoice Status"),
              name: "InvoiceStatus",
              value: "",
              placeholder: this.$t("Select"),
              visibility: true,
              isSearch: false,
              config: {
                options: [],
                actionButtons: { clear: true },
                isMultiple: false,
                minSearchLength: 0
              }
            }
          ]
        },
        {
          layoutType: "triple",
          Data: [
            {
              astype: "DateRangeField",
              label: this.$t("Invoice Date"),
              name: "InvoiceDate",
              value: "",
              placeholder: "",
              config: {
                format: "MM/DD/YYYY",
                maxDate: false,
                onChange: this.setTimerDate,
                datePickerConfig: {
                  useCurrent: true,
                  showClear: true,
                  showClose: true,
                  allowInputToggle: false,
                  minDate: true,
                  maxDate: true,
                  widgetPositioning: {
                    horizontal: 'right',
                    vertical: 'bottom'
                  }
                },
                secondDatePickerConfig: {
                  useCurrent: false,
                  showClear: true,
                  showClose: true,
                  allowInputToggle: false,
                  minDate: true,
                  maxDate: true,
                  widgetPositioning: {
                    horizontal: 'right',
                    vertical: 'bottom'
                  }
                }
              },
              validationRules: { required: true }
            }
          ]
        }
      ],

      buttons: [
        {
          type: "submit",
          class: "btn btn-success",
          text: "<i class='fa fa-search pr-2'></i>Search"
        },
        {
          type: "button",
          class: "btn btn-danger",
          text: "<i class='fa fa-close pr-2'></i>Clear all",
          onClick: this.ClearAll
        }
      ]
    };
  },

  created() {
    this.userId = this.GetUserInfo.ID;
    this.companyId = this.GetUserInfo.CompanyId;
    this.UserType = this.GetUserInfo.UserType;

    this.DataLoaded = 1;
    this.GetClient();
    this.GetCommonStatusCodes();
  },

  methods: {
    /* =======================
       Helpers
    ======================= */
    formatDate(value) {
      if (!value) return '';
      const m = moment(value);
      return m.isValid() ? m.format('MM-DD-YYYY') : '';
    },

    setTimerDate(x, y) {
      if (y.name === "InvoiceDate") {
        this.$refs.BarcodeReport.updateProperty(
          "InvoiceDate",
          "config.secondDatePickerConfig.minDate",
          x
        );
        this.$refs.BarcodeReport.UpdateKeyValue();
      }
    },

    /* =======================
       Submit
    ======================= */
    onSubmit(e) {
        debugger;
      const vm = this;
      vm.isLoading = true;
      vm.loadKey = Date.now();
      vm.reportPath = '';
      vm.parameter = [];

      const invoiceFrom = vm.$refs.BarcodeReport.getPropertyValue(
        "InvoiceDate",
        "value"
      );
      const invoiceTo = vm.$refs.BarcodeReport.getPropertyValue(
        "InvoiceDate",
        "secondValue"
      );

      let myObj = {
        //revenuecomparisonreport is Invoice Summary Report
        reportName: "revenuecomparisonreport",
        ClientIds: e.ContractName || '',
        DivisionId: e.InvoiceGrouping || '',
        StatusIds: e.InvoiceStatus || '',
        DueDateFrom: vm.formatDate(invoiceFrom),
        DueDateTo: vm.formatDate(invoiceTo)
      };

      DataServices.ReportMain(JSON.stringify(myObj))
        .then(response => {
          vm.reportPath = response.data.reportpath;
          vm.parameter = response.data.parameters;
          vm.isLoading = false;
        })
        .catch(error => {
          console.error("Error loading report:", error);
          vm.isLoading = false;
        });
    },

    /* =======================
       Clear
    ======================= */
    ClearAll() {
      const vm = this;

      vm.$refs.BarcodeReport.updateProperty("ContractName", "value", '');
      vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "value", '');
      vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "config.options", []);
      vm.$refs.BarcodeReport.updateProperty("InvoiceStatus", "value", '');

      vm.$refs.BarcodeReport.updateProperty("InvoiceDate", "value", '');
      vm.$refs.BarcodeReport.updateProperty("InvoiceDate", "secondValue", '');

      vm.reportPath = '';
      vm.parameter = [];
      vm.$refs.BarcodeReport.validateForm.reset();
    },

    /* =======================
       Dropdown loaders
    ======================= */
    GetClient() {
      const vm = this;
      const params = 'pageNumber=&pageSize=&Reqfrom=CUSTOMREPORT&search=null&userId=null';

      DataServices.GetClient(params).then(response => {
        const options = response.data.map(item => ({
          text: item.CHILD_NAME,
          value: item.CHILD_USER_ID,
          status: 'Active'
        }));

        vm.$refs.BarcodeReport.updateProperty(
          "ContractName",
          "config.options",
          options
        );
        vm.$refs.BarcodeReport.UpdateKeyValue();
      });
    },

    onContractChange(value, selectedValue) {
      const vm = this;

      vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "value", '');
      vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "config.options", []);

      if (selectedValue) {
        vm.GetInvoiceGrouping(selectedValue);
      }
    },

    GetInvoiceGrouping(clientId) {
      const vm = this;
      const url = `ClientId=${clientId}&UtilityIds=`;

      DataServices.GetInvoiceGrouping(url).then(response => {
        const options = response.data.map(item => ({
          text: item.NOTE,
          value: item.ID,
          status: 'Active'
        }));

        vm.$refs.BarcodeReport.updateProperty(
          "InvoiceGrouping",
          "config.options",
          options
        );
        vm.$refs.BarcodeReport.UpdateKeyValue();
      });
    },

    GetCommonStatusCodes() {
      const vm = this;
      const url = `statusTypeName=ClientBilling`;

      DataServices.GetCommonStatusCodes(url).then(response => {
        const options = response.data.map(item => ({
          text: item.STATUS_NAME,
          value: item.STATUS_ID,
          status: 'Active'
        }));

        vm.$refs.BarcodeReport.updateProperty(
          "InvoiceStatus",
          "config.options",
          options
        );
        vm.$refs.BarcodeReport.UpdateKeyValue();
      });
    }
  }
};
</script>
