<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer v-if="parameter.length > 0" :key="loadKey" :viewerId="'viewer_' + loadKey" :parameter="parameter" :reportPath="reportPath">
                            </ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
import moment from 'moment';
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            isLoading: false,
            loadKey: 0,
            reportPath: null,
            parameter: [],
            DataLoaded: 0,
            ClientIds: 0,
            FormSchema: [{
                    layoutType: "triple",
                    Data: [{
                            astype: "SearchableSelectField",
                            label: "Contract Name",
                            name: "ContractName",
                            value: "",
                            placeholder: this.$t('Select'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                isMultiple: false,
                                minSearchLength: 0,
                                groupFields: [],
                                actionButtons: {
                                    clear: true
                                },
                                onChange: this.CommonOnChange
                            },
                            validationRules: {
                                required: false
                            }
                        },
                        {
                            astype: "SearchableSelectField",
                            label: "Utility Name",
                            name: "UtilityName",
                            value: "",
                            placeholder: this.$t('Select'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                groupFields: [],
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                }
                            },
                            validationRules: {
                                required: false
                            }
                        },
                        {
                            astype: "SearchableSelectField",
                            label: "Invoice Grouping",
                            name: "InvoiceGrouping",
                            value: "",
                            placeholder: this.$t('Select'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                groupFields: [],
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                }
                            },
                            validationRules: {
                                required: false
                            }
                        }
                    ]
                },
                {
                    layoutType: "triple",
                    Data: [{
                            astype: "SearchableSelectField",
                            label: "Cost Centers",
                            name: "CostCenter",
                            value: "",
                            placeholder: this.$t('Select'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                groupFields: [],
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                }
                            },
                            validationRules: {
                                required: false
                            }
                        },
                        {
                            astype: "DateRangeField",
                            label: this.$t('Invoice Date'),
                            name: "InvoiceDateFrom",
                            value: "",
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                maxDate: false,
                                onChange: this.setTimerDate,
                                datePickerConfig: {
                                    useCurrent: true,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                                secondDatePickerConfig: {
                                    useCurrent: false,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t("State"),
                            name: "State",
                            value: "",
                            placeholder: this.$t('Select'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                groupFields: [],
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                }
                            },
                            validationRules: {
                                required: false
                            }
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t("Group By"),
                            name: "GroupBy",
                            value: {
                                text: 'Cost Centers',
                                displayValue: 'Cost Centers',
                                value: 'CostCenter',
                                description: null,
                                groupText: null,
                                groupValue: null,
                                metaData: null
                            },
                            placeholder: this.$t('Select'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [{
                                    text: 'Cost Centers',
                                    displayValue: 'Cost Centers',
                                    value: 'CostCenter',
                                    description: null,
                                    groupText: null,
                                    groupValue: null,
                                    metaData: null
                                }, {
                                    text: 'Contract',
                                    displayValue: 'Contract',
                                    value: 'Customer',
                                    description: null,
                                    groupText: null,
                                    groupValue: null,
                                    metaData: null
                                }, {
                                    text: 'Invoice Grouping',
                                    displayValue: 'Invoice Grouping',
                                    value: 'Invoice Grouping',
                                    description: null,
                                    groupText: null,
                                    groupValue: null,
                                    metaData: null
                                }, {
                                    text: 'State',
                                    displayValue: 'State',
                                    value: 'State',
                                    description: null,
                                    groupText: null,
                                    groupValue: null,
                                    metaData: null
                                }, {
                                    text: 'Utility Name',
                                    displayValue: 'Utility Name',
                                    value: 'UtilityName',
                                    description: null,
                                    groupText: null,
                                    groupValue: null,
                                    metaData: null
                                }]
                            },
                            validationRules: {
                                required: true
                            }
                        }
                    ]
                }
            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DataLoaded = 1;
        await vm.GetClient();
        await vm.GetDDLStateList();
        await vm.GetCostCenters();
    },
    methods: {
        setTimerDate: function (x, y, z) {
            var vm = this;
            if (y.name == "InvoiceDateFrom") {
                vm.$refs.BarcodeReport.updateProperty("InvoiceDateFrom", "config.secondDatePickerConfig.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        },
        formatDate(value) {
            if (!value) return null;
            const m = moment(value);
            return m.isValid() ? m.format('MM-DD-YYYY') : null;
        },
        async onSubmit(e) {
            var vm = this;
            vm.isLoading = true;
            vm.loadKey = Date.now();
            vm.reportPath = '';
            vm.parameter = [];

            vm.InvoiceDateFrom = vm.$refs.BarcodeReport.getPropertyValue("InvoiceDateFrom", "value");
            vm.InvoiceDateTo = vm.$refs.BarcodeReport.getPropertyValue("InvoiceDateFrom", "secondValue");

            let myObj = {
                reportName: "monthlyrevenuesummaryreport",
                ClientIds: e.ContractName ? e.ContractName : '',
                UtilityIds: e.UtilityName && e.UtilityName.length > 0 ? e.UtilityName.join(",") : '',
                DivisionId: e.InvoiceGrouping && e.InvoiceGrouping.length > 0 ? e.InvoiceGrouping.join(",") : '',
                CostCenterId: e.CostCenter && e.CostCenter.length > 0 ? e.CostCenter.join(",") : '',
                dateFrom: vm.formatDate(vm.InvoiceDateFrom),
                dateTo: vm.formatDate(vm.InvoiceDateTo),
                State: e.State && e.State.length > 0 ? e.State.join(",") : '',
                GroupBy: e.GroupBy && e.GroupBy.value ? e.GroupBy.value : 'CostCenter'
            }

            debugger;
            var postString = JSON.stringify(myObj);
            try {
                let response = await DataServices.ReportMain(postString);
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
            } catch (error) {
                console.error("Error loading report:", error);
            } finally {
                vm.isLoading = false;
            }
        },
        ClearAll: function () {
            var vm = this;
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[1].config.options = [];
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[0].Data[2].config.options = [];
            (vm.FormSchema)[1].Data[0].value = '';
            (vm.FormSchema)[1].Data[0].config.options = [];
            (vm.FormSchema)[1].Data[1].value = '';
            (vm.FormSchema)[1].Data[1].secondValue = '';
            (vm.FormSchema)[1].Data[2].value = '';
            (vm.FormSchema)[1].Data[2].config.options = [];
            (vm.FormSchema)[1].Data[3].value = {
                text: 'Cost Centers',
                displayValue: 'Cost Centers',
                value: 'CostCenter',
                description: null,
                groupText: null,
                groupValue: null,
                metaData: null
            };
            vm.reportPath = '';
            vm.parameter = [];
            vm.loadKey = 0;
            vm.$refs.BarcodeReport.validateForm.reset();
        },
        async CommonOnChange(value, selectedId) {
            var vm = this;
            vm.ClientIds = selectedId;
            // Reset dependents
            vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", []);
            vm.$refs.BarcodeReport.updateProperty("UtilityName", "value", []);
            vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "config.options", []);
            vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "value", []);
            vm.$refs.BarcodeReport.UpdateKeyValue();
            if (vm.ClientIds && vm.ClientIds > 0) {
                await vm.GetUtilityByClient();
                await vm.GetDivisionListByCilentId();
            }
        },
        async GetClient() {
            var vm = this;
            vm.isLoading = true;
            var params = 'pageNumber=&pageSize=&Reqfrom="CUSTOM"&search=null&userId=null';
            try {
                let response = await DataServices.GetClient(params);
                if (response.data && response.data.length > 0) {
                    let clientOptions = response.data.map(item => ({
                        text: item.CHILD_NAME,
                        displayValue: item.CHILD_NAME,
                        value: item.CHILD_USER_ID,
                        description: null,
                        groupText: null,
                        groupValue: null,
                        metaData: null
                    }));
                    vm.$refs.BarcodeReport.updateProperty("ContractName", "config.options", clientOptions);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                } else {
                    vm.$refs.BarcodeReport.updateProperty("ContractName", "config.options", []);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } catch (error) {
                console.error("Error fetching clients:", error);
                vm.$refs.BarcodeReport.updateProperty("ContractName", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            } finally {
                vm.isLoading = false;
            }
        },
        async GetUtilityByClient() {
            var vm = this;
            if (vm.ClientIds > 0) {
                var url = `clientId=${vm.ClientIds}&configid=0&Reqfrom=&clientIds=`;
                try {
                    let response = await DataServices.GetUtilityByClient(url);
                    if (response.data && response.data.length > 0) {
                        let utilityOptions = response.data.map(item => ({
                            text: item.UTILITY_NAME,
                            displayValue: item.UTILITY_NAME,
                            value: item.UTILITY_ID,
                            description: null,
                            groupText: null,
                            groupValue: null,
                            metaData: null
                        }));
                        vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", utilityOptions);
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    } else {
                        vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", []);
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                } catch (error) {
                    console.error("Error fetching utilities:", error);
                    vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", []);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } else {
                vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
                console.warn("No valid ClientIds to fetch utility data.");
            }
        },
        async GetDivisionListByCilentId() {
            var vm = this;
            if (vm.ClientIds > 0) {
                var url = `clientId=${vm.ClientIds}`;
                try {
                    let response = await DataServices.GetDivisionListByCilentId(url);
                    if (response.data && response.data.length > 0) {
                        let divisionOptions = response.data.map(item => ({
                            text: item.NAME,
                            displayValue: item.NAME,
                            value: item.DIVISIONS_ID,
                            description: null,
                            groupText: null,
                            groupValue: null,
                            metaData: null
                        }));
                        vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "config.options", divisionOptions);
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    } else {
                        vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "config.options", []);
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                } catch (error) {
                    console.error("Error fetching divisions:", error);
                    vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "config.options", []);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } else {
                vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
                console.warn("No valid ClientIds to fetch division list.");
            }
        },
        async GetCostCenters() {
            var vm = this;
            vm.isLoading = true;
            try {
                let response = await DataServices.GetCostCenters();
                if (response.data && response.data.length > 0) {
                    let costCenterOptions = response.data.map(item => ({
                        text: item.text,
                        displayValue: item.text,
                        value: item.value,
                        description: null,
                        groupText: null,
                        groupValue: null,
                        metaData: null
                    }));
                    vm.$refs.BarcodeReport.updateProperty("CostCenter", "config.options", costCenterOptions);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                } else {
                    vm.$refs.BarcodeReport.updateProperty("CostCenter", "config.options", []);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } catch (error) {
                console.error("Error fetching cost centers:", error);
                vm.$refs.BarcodeReport.updateProperty("CostCenter", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            } finally {
                vm.isLoading = false;
            }
        },
        async GetDDLStateList() {
            var vm = this;
            var params = `CountryId=223&InclueCandaState=true`;
            try {
                let response = await DataServices.GetDDLStateList(params);
                if (response.data && response.data.length > 0) {
                    let stateOptions = response.data.map(item => ({
                        text: item.STATE_NAME + '(' + item.ISO_CODE_3 + ')',
                        displayValue: item.STATE_NAME + '(' + item.ISO_CODE_3 + ')',
                        value: item.STATE_ID,
                        description: null,
                        groupText: null,
                        groupValue: null,
                        metaData: null
                    }));
                    vm.$refs.BarcodeReport.updateProperty("State", "config.options", stateOptions);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                } else {
                    vm.$refs.BarcodeReport.updateProperty("State", "config.options", []);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } catch (error) {
                console.error("Error fetching states:", error);
                vm.$refs.BarcodeReport.updateProperty("State", "config.options", []);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        }
    }
}
</script>