<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer v-if="parameter.length > 0" :key="loadKey" :viewerId="'viewer_' + loadKey" :parameter="parameter" :reportPath="reportPath">
                            </ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
import moment from 'moment';
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            isLoading: false,
            reportPath: null,
            parameter: [],
            loadKey: 0,
            DataLoaded: 0,
            DateFormat: "M/D/YYYY",
            FormSchema: [{
                    layoutType: "triple",
                    Data: [{
                            astype: "SearchableSelectField",
                            label: this.$t('CONTRACTNAME'),
                            name: "ContractName",
                            value: "",
                            placeholder: this.$t('SelectClient'),
                            visibility: true,
                            isSearch: true,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: false,
                                    active: false,
                                    inactive: false,
                                    clear: false
                                },
                                itemFields: ['text','status'],
                                isMultiple: false,
                                groupFields: ['groupText'],
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                                onChange: this.onSelectionChange
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t('Utility Name'),
                            name: "UtilityName",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Utility Name'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                },
                                groupFields: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t("Modified By"),
                            name: "ModifiedBy",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Modified By'),
                            visibility: true,
                            isSearch: true,
                            config: {
                                options: [],
                                groupFields: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                },
                            },
                            validationRules: {
                                required: false
                            }
                        }
                    ]
                },
                {
                    layoutType: "triple",
                    Data: [{
                            astype: "DateRangeField",
                            label: this.$t('Resolved Date'),
                            name: "ResolvedDateFrom",
                            value: "",
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                maxDate: false,
                                onChange: this.setTimerDate,
                                datePickerConfig: {
                                    useCurrent: true,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                                secondDatePickerConfig: {
                                    useCurrent: false,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "DateRangeField",
                            label: this.$t('Flag Date'),
                            name: "FlagDateFrom",
                            value: "",
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                maxDate: false,
                                onChange: this.setTimerDate,
                                datePickerConfig: {
                                    useCurrent: true,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                                secondDatePickerConfig: {
                                    useCurrent: false,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "textField",
                            label: this.$t("Ticket Number"),
                            name: "TicketNumber",
                            value: "",
                            placeholder: "Ticket Number"
                        }
                    ]
                },
                {
                    layoutType: "triple",
                    Data: [{
                            astype: "DateRangeField",
                            label: this.$t('Work_Date'),
                            name: "WorkDateFrom",
                            value: "",
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                maxDate: false,
                                onChange: this.setTimerDate,
                                datePickerConfig: {
                                    useCurrent: true,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                                secondDatePickerConfig: {
                                    useCurrent: false,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t("Cost Centers"),
                            name: "CostCenters",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Cost Centers'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                isMultiple: false,
                                minSearchLength: 0,
                                actionButtons: {
                                    clear: true
                                },
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                }
                            },
                            validationRules: {
                                required: false
                            }
                        }
                    ]
                }
            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DateFormat = vm.GetUserInfo.DateFormat || "M/D/YYYY";
        vm.DataLoaded = 1;
        await vm.GetCostCenters();
        await vm.fetchclientlist();
        await vm.GetUsers();
    },
    methods: {
        formatDate(value) {
            if (!value) return null;
            const m = moment(value);
            return m.isValid() ? m.format('MM-DD-YYYY') : null;
        },
        setTimerDate: function (x, y, z) {
            var vm = this;
            if (y.name == "ResolvedFromdate") {
                vm.$refs.BarcodeReport.updateProperty("ResolvedToDate", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
            if (y.name == "FlagFromdate") {
                vm.$refs.BarcodeReport.updateProperty("FlagToDate", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
            if (y.name == "WorkDateFromdate") {
                vm.$refs.BarcodeReport.updateProperty("WorkDateToDate", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        },
        ClearAll: function () {
            var vm = this;
            vm.FormSchema[0].Data[1].config.options = [];
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[1].Data[0].value = '';
            (vm.FormSchema)[1].Data[0].secondValue = '';
            (vm.FormSchema)[1].Data[1].value = '';
            (vm.FormSchema)[1].Data[1].secondValue = '';
            (vm.FormSchema)[1].Data[2].value = '';
            (vm.FormSchema)[2].Data[0].value = '';
            (vm.FormSchema)[2].Data[0].secondValue = '';
            (vm.FormSchema)[2].Data[1].value = '';
            vm.reportPath = '';
            vm.parameter = [];
            vm.loadKey = 0;
            vm.$refs.BarcodeReport.validateForm.reset();
        },
        fetchclientlist: function () {
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOMREPORT`;
            DataServices.getClientList(url).then(response => {
                vm.isLoading = false;
                vm.ClientData = response.data.items;
                vm.$refs.BarcodeReport.updateProperty("ContractName", "config.options", vm.ClientData);
                vm.$refs.BarcodeReport.UpdateKeyValue();

            }).catch(error => {
                vm.isLoading = false;
                vm.ClientData = [];
                vm.$refs.BarcodeReport.updateProperty("ContractName", "config.options", vm.ClientData);
                vm.$refs.BarcodeReport.UpdateKeyValue();
                console.error('Error fetching client list:', error);
            }).finally(() => {
                vm.isLoading = false;
            });
        },
        onSelectionChange(value, x) {
            var vm = this;
            vm.isLoading = true;
            if (x.length > 0) {
                vm.selectedClientId = x;
                vm.clientId = x;
            } else {
                vm.selectedClientId = null;
                vm.clientId = null;
            }
            var url = `clientId=${vm.selectedClientId}&configId=&reqFrom=&clientIds=`;
            DataServices.getUtilityList(url).then(response => {
                let SelectedUtilityList = [];
                var UtilityList = response.data;
                if (UtilityList != null) {
                    UtilityList.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.UTILITY_NAME,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.UTILITY_NAME,
                            value: item.UTILITY_ID
                        };
                        SelectedUtilityList.push(obj);
                    });
                    vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", SelectedUtilityList);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            }).catch(error => {
                vm.isLoading = false;
                vm.UtilityList = [];
                vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", []);
                vm.$refs.BarcodeReport.updateProperty("UtilityName", "value", '');
            }).finally(() => {
                vm.isLoading = false;
            });
        },
        GetUsers: async function () {
            var vm = this;
            var params = `isType=false&moduleName=InvoiceReport`;
            await DataServices.GetUsers(params).then((response) => {
                let SelectedUsersList = [];
                var UserList = response.data;
                if (UserList != null) {
                    UserList.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.UserName,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.UserName,
                            value: item.UserId
                        };
                        SelectedUsersList.push(obj);
                    });
                    vm.$refs.BarcodeReport.updateProperty("ModifiedBy", "config.options", SelectedUsersList);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        GetCostCenters: async function () {
            var vm = this;
            await DataServices.GetCostCenters().then((response) => {
                let SelectedCostCenterList = [];
                var CostCenterList = response.data;
                if (CostCenterList != null) {
                    CostCenterList.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.text,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.text,
                            value: item.value
                        };
                        SelectedCostCenterList.push(obj);
                    });
                    vm.$refs.BarcodeReport.updateProperty("CostCenters", "config.options", SelectedCostCenterList);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        async onSubmit(e) {
            var vm = this;
            vm.isLoading = true;
            vm.loadKey = Date.now();
            vm.reportPath = '';
            vm.parameter = [];
            
            vm.ResolvedDateFrom = vm.$refs.BarcodeReport.getPropertyValue("ResolvedDateFrom", "value");
            vm.ResolvedDateTo = vm.$refs.BarcodeReport.getPropertyValue("ResolvedDateFrom", "secondValue");
            vm.FlagDateFrom = vm.$refs.BarcodeReport.getPropertyValue("FlagDateFrom", "value");
            vm.FlagDateTo = vm.$refs.BarcodeReport.getPropertyValue("FlagDateFrom", "secondValue");
            vm.WorkDateFrom = vm.$refs.BarcodeReport.getPropertyValue("WorkDateFrom", "value");
            vm.WorkDateTo = vm.$refs.BarcodeReport.getPropertyValue("WorkDateFrom", "secondValue");

            let myObj = {
                reportName: "flagdetailreport",
                ClientIds: e.ContractName,
                UtilityIds: e.UtilityName.length > 0 ? e.UtilityName.join(",") : '',
                userIds: e.ModifiedBy.length > 0 ? e.ModifiedBy.join(",") : '',
                resolvedFromDate: vm.formatDate(vm.ResolvedDateFrom),
                resolvedToDate: vm.formatDate(vm.ResolvedDateTo),
                createdFromDate: vm.formatDate(vm.FlagDateFrom),
                createdToDate: vm.formatDate(vm.FlagDateTo),
                TicketNumber: e.TicketNumber,
                WorkDateFrom: vm.formatDate(vm.WorkDateFrom),
                WorkDateTo: vm.formatDate(vm.WorkDateTo),
                CostCenterId: e.CostCenters
            };
            var postString = JSON.stringify(myObj);
            DataServices.ReportMain(postString).then(function (response) {
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
                vm.isLoading = false;
            }).catch(function (error) {
                console.error("Error loading report:", error);
                vm.isLoading = false;
            });
        }
    }
};
</script>